styles.css:
/*
Theme Name: WordPress 2026 LMHG
Theme URI: http://100.70.222.25:8093/
Author: Louisville Mental Health Group
Description: Fresh Gutenberg-native block theme for the 2026 WordPress rebuild.
Version: 0.1.0
Requires at least: 6.6
Tested up to: 7.0
Requires PHP: 8.0
Text Domain: wordpress-2026
*/
:root { --wp2026-green: #31584a; --wp2026-deep: #152821; --wp2026-mint: #dce9df; --wp2026-cream: #f7f3ed; --wp2026-clay: #a75f3f; --wp2026-ink: #1f2a26; --wp2026-soft: #f8fbf8; }
body { color: var(--wp2026-ink); background: #ffffff; }
a { color: var(--wp2026-green); }
body, button, input, select, textarea, h1, h2, h3, h4, h5, h6, .wp-block-heading { font-family: Inter, Arial, sans-serif; }
h1, h2, h3, h4, h5, h6, .wp-block-heading { letter-spacing: 0; line-height: 1.08; max-width: 100%; overflow-wrap: anywhere; text-wrap: balance; white-space: normal; }
.lmhg-skip-link { background: var(--wp2026-deep); border: 2px solid var(--wp2026-clay); border-radius: 6px; color: #ffffff; font-weight: 800; left: 16px; padding: 0.65rem 0.9rem; position: absolute; text-decoration: none; top: 8px; transform: translateY(-150%); transition: transform 120ms ease; z-index: 1000; }
.lmhg-skip-link:focus { color: #ffffff; transform: translateY(0); }
.lmhg-main-content:focus { outline: none; }
.wp2026-site-header { background: #ffffff; border-bottom: 1px solid rgba(21, 40, 33, 0.12); position: sticky; top: 0; z-index: 20; }
.wp2026-header-inner { min-height: 46px; gap: 8px 26px; padding-block: 11px 9px; }
.wp2026-brand { align-items: flex-start; flex-direction: column; gap: 1px; min-width: min(100%, 310px); }
.wp2026-brand .wp-block-site-title a { text-decoration: none; color: var(--wp2026-deep); }
.wp2026-header-nav { gap: 20px; align-items: center; }
.wp2026-primary-nav .wp-block-navigation-item__content { font-size: 0.88rem; }
.wp2026-header-cta, .wp2026-hero-actions, .wp2026-closing-actions { display: flex; flex-direction: row; gap: 0.9rem; align-items: center; }
.wp2026-header-cta.wp-block-buttons,
.wp2026-hero-actions.wp-block-buttons,
.wp2026-closing-actions.wp-block-buttons {
  flex-direction: row !important;
  flex-wrap: wrap;
  gap: 0.9rem !important;
}
.wp2026-header-cta .wp-block-button,
.wp2026-hero-actions .wp-block-button,
.wp2026-closing-actions .wp-block-button {
  margin: 0 !important;
}
.wp2026-header-cta .wp-block-button__link, .wp2026-site-footer .wp-block-button__link, .wp-block-button__link { align-items: center; background: var(--wp2026-green); border: 1px solid var(--wp2026-clay); border-radius: 6px; box-sizing: border-box; color: #ffffff; display: inline-flex; justify-content: center; line-height: 1.1; min-height: 46px; padding: 0.58rem 0.9rem; }
.wp-block-button.is-style-outline > .wp-block-button__link,
.wp-block-button.is-style-outline .wp-block-button__link {
  background: transparent;
  border-color: var(--wp2026-clay);
}
.wp2026-template-home, .wp2026-template-page, .wp2026-template-service-page, .wp2026-template-specialty-page, .wp2026-template-location-access-page, .wp2026-template-faq-page, .wp2026-template-team-page, .wp2026-template-contact-page, .wp2026-template-trust-page, .wp2026-template-legal-utility-page, .wp2026-template-article-page, .wp2026-template-services-hub, .wp2026-template-specialties-hub, .wp2026-template-article-hub, .wp2026-template-faq-hub { box-sizing: border-box; padding-block: clamp(32px, 5vw, 72px); padding-inline: max(18px, calc((100vw - 1180px) / 2)); width: 100%; }
.wp2026-template-home { padding-block: 0; padding-inline: 0; }
.wp2026-page-title { font-size: clamp(1.7rem, 4vw, 3.35rem); margin-left: auto; margin-right: auto; max-width: 100%; overflow-wrap: anywhere; position: relative; text-wrap: balance; white-space: normal; width: min(calc(100% - 36px), 980px); z-index: 0; }
.wp2026-template-kicker { display: none; }
.wp2026-breadcrumbs { color: var(--wp2026-clay); font-size: 0.9rem; font-weight: 700; letter-spacing: 0; margin-bottom: 0.8rem; }
.wp2026-breadcrumbs a { color: var(--wp2026-green); text-decoration: none; }
.wp2026-lead { font-size: clamp(1.1rem, 1.5vw, 1.28rem); line-height: 1.65; max-width: 860px; }
.wp2026-content-section { box-sizing: border-box; margin-left: auto; margin-right: auto; margin-top: 2rem; max-width: 860px; width: min(calc(100% - 36px), 860px); }
.wp2026-page-cta { box-sizing: border-box; margin-left: auto; margin-right: auto; margin-top: 2rem; max-width: 860px; padding: clamp(20px, 4vw, 36px); background: var(--wp2026-mint); border-left: 5px solid var(--wp2026-green); width: min(calc(100% - 36px), 860px); }
.wp2026-site-footer { background: var(--wp2026-deep); color: #f9fbf8; margin-top: 0; padding-block: 56px 28px; }
.wp2026-site-footer a { color: #f9fbf8; }
.wp2026-footer-columns { gap: clamp(24px, 4vw, 56px); }
.wp2026-site-footer ul { list-style: none; padding-left: 0; }
@media (max-width: 780px) { .wp2026-header-inner, .wp2026-header-nav { align-items: flex-start; } .wp2026-brand { display: flex; } }

/* Rendered semantic hooks for WordPress Playground template-part output. */
header.wp-block-template-part {
  background: #ffffff;
  border-bottom: 1px solid rgba(21, 40, 33, 0.12);
  display: grid;
  grid-template-columns: max-content minmax(0, 1fr) max-content;
  grid-template-rows: auto auto;
  align-items: center;
  column-gap: clamp(22px, 3vw, 42px);
  row-gap: 1px;
  min-height: 50px;
  padding: 12px max(18px, calc((100vw - 1180px) / 2)) 10px;
  position: sticky;
  top: 0;
  z-index: 20;
}

header.wp-block-template-part .wp-block-site-title,
header.wp-block-template-part .wp-block-site-tagline,
header.wp-block-template-part .wp-block-button {
  margin: 0;
}

header.wp-block-template-part .wp-block-site-title {
  grid-column: 1;
  grid-row: 1;
  line-height: 1.05;
  white-space: nowrap;
}

header.wp-block-template-part .wp-block-site-title a {
  color: var(--wp2026-deep);
  text-decoration: none;
}

header.wp-block-template-part .wp-block-site-tagline {
  color: var(--wp2026-green);
  font-size: 0.72rem;
  grid-column: 1;
  grid-row: 2;
  line-height: 1.1;
  opacity: 0.88;
  white-space: nowrap;
}

header.wp-block-template-part .wp-block-navigation {
  grid-column: 2;
  grid-row: 1 / span 2;
  justify-self: end;
  margin-left: 0;
}

header.wp-block-template-part .wp-block-navigation__container {
  gap: clamp(0.8rem, 1.4vw, 1.25rem);
}

@media (min-width: 782px) {
  .wp2026-primary-nav .wp-block-navigation__submenu-container .wp-block-navigation__submenu-container {
    left: 100% !important;
    right: auto !important;
    top: -1px;
  }
}

header.wp-block-template-part > .wp-block-button {
  grid-column: 3;
  grid-row: 1 / span 2;
  justify-self: end;
}

header.wp-block-template-part > .wp-block-button .wp-block-button__link {
  min-height: 46px;
  padding: 0.58rem 0.9rem;
  white-space: nowrap;
}

footer.wp-block-template-part {
  background: var(--wp2026-deep);
  color: #f9fbf8;
  margin-top: 0;
  padding: 56px max(18px, calc((100vw - 1180px) / 2)) 28px;
}

footer.wp-block-template-part a {
  color: #f9fbf8;
  text-decoration-color: rgba(249, 251, 248, 0.38);
  text-underline-offset: 0.18em;
}

footer.wp-block-template-part .wp2026-footer-shell {
  max-width: 1180px;
  margin-inline: auto;
  width: 100%;
}

.wp2026-footer-shell {
  max-width: 1180px;
  margin-inline: auto;
  width: 100%;
}

footer.wp-block-template-part .wp2026-footer-grid {
  display: grid !important;
  gap: clamp(28px, 4vw, 56px);
  grid-template-columns: minmax(320px, 1.45fr) repeat(3, minmax(140px, 1fr));
  max-width: 1180px;
  margin-inline: auto;
}

.wp2026-footer-grid {
  display: grid !important;
  gap: clamp(28px, 4vw, 56px);
  grid-template-columns: minmax(320px, 1.45fr) repeat(3, minmax(140px, 1fr));
  max-width: 1180px;
  margin-inline: auto;
}

footer.wp-block-template-part .wp2026-footer-grid > .wp-block-group {
  margin: 0 !important;
  min-width: 0;
}

.wp2026-footer-grid > .wp-block-group {
  margin: 0 !important;
  min-width: 0;
}

.wp2026-footer-title {
  color: #ffffff;
  font-size: clamp(1.2rem, 1.8vw, 1.55rem);
  margin: 0 0 0.75rem;
  white-space: normal;
}

.wp2026-footer-heading {
  color: #ffffff;
  font-size: 0.95rem;
  letter-spacing: 0;
  margin: 0 0 0.85rem;
  white-space: normal;
}

.wp2026-footer-summary,
.wp2026-footer-contact,
.wp2026-footer-link-stack,
.wp2026-footer-note,
.wp2026-footer-copy {
  color: rgba(249, 251, 248, 0.84);
  font-size: 0.94rem;
  line-height: 1.65;
}

.wp2026-footer-summary {
  max-width: 360px;
}

.wp2026-footer-link-stack {
  display: block;
  margin: 0;
}

.wp2026-footer-link-stack a {
  display: inline-block;
  margin-bottom: 0.45rem;
}

.wp2026-footer-actions {
  margin-top: 1.4rem;
}

.wp2026-footer-rule {
  border-color: rgba(249, 251, 248, 0.22);
  margin: 38px 0 18px;
}

.wp2026-footer-bottom {
  align-items: flex-start;
  gap: 1rem 2rem;
}

.wp2026-footer-note {
  max-width: 760px;
  margin: 0;
}

.wp2026-footer-copy {
  margin: 0;
  white-space: nowrap;
}

footer.wp-block-template-part > p,
footer.wp-block-template-part > hr {
  max-width: 900px;
  margin-left: auto;
  margin-right: auto;
}

@media (max-width: 1120px) {
  header.wp-block-template-part {
    grid-template-columns: minmax(0, 1fr) max-content;
  }

  header.wp-block-template-part .wp-block-site-title {
    grid-column: 1;
    grid-row: 1;
  }

  header.wp-block-template-part > .wp-block-button {
    grid-column: 2;
    grid-row: 1;
  }

  header.wp-block-template-part .wp-block-site-tagline {
    grid-column: 1;
    grid-row: 2;
  }

  header.wp-block-template-part .wp-block-navigation {
    grid-column: 2;
    grid-row: 2;
  }
}

@media (max-width: 760px) {
  header.wp-block-template-part {
    grid-template-columns: 1fr;
  }

  header.wp-block-template-part .wp-block-site-title,
  header.wp-block-template-part .wp-block-site-tagline,
  header.wp-block-template-part .wp-block-navigation,
  header.wp-block-template-part > .wp-block-button {
    grid-column: 1;
    grid-row: auto;
    justify-self: start;
  }

  header.wp-block-template-part .wp-block-site-tagline {
    white-space: normal;
  }
}

/* Homepage pilot Gutenberg sections. */
.wp2026-home-hero,
.wp2026-start-bar,
.wp2026-home-services,
.wp2026-home-closing {
  box-sizing: border-box;
  margin-inline: auto;
  max-width: none !important;
  padding: clamp(32px, 5vw, 72px) max(18px, calc((100vw - 1180px) / 2));
  width: 100% !important;
}

.wp2026-start-bar {
  background: linear-gradient(180deg, #ffffff 0%, var(--wp2026-soft) 100%);
  border-bottom: 1px solid rgba(21, 40, 33, 0.08);
  border-top: 0;
  padding-block: clamp(34px, 4.2vw, 54px);
}

.wp2026-start-inner {
  max-width: 980px;
  margin-inline: auto;
  width: 100%;
}

.wp2026-start-inner > .wp2026-start-heading,
.wp2026-start-inner > .wp2026-start-lead {
  margin-left: auto !important;
  margin-right: auto !important;
  text-align: center;
}

.wp2026-start-heading {
  font-size: clamp(1.35rem, 2.1vw, 1.8rem);
  margin: 0;
}

.wp2026-start-lead {
  font-size: clamp(1rem, 1.15vw, 1.08rem);
  line-height: 1.6;
  margin: 0.6rem 0 0;
  max-width: 720px;
  overflow-wrap: break-word;
  white-space: normal;
}

.wp2026-start-grid {
  display: grid;
  gap: 16px;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  margin: clamp(28px, 3.2vw, 40px) auto 0;
  max-width: 980px;
  width: 100%;
}

.wp2026-start-grid > .wp2026-start-step {
  margin-block-start: 0 !important;
  margin-top: 0 !important;
}

.wp2026-start-step {
  align-items: center;
  background: #ffffff;
  border: 1px solid rgba(21, 40, 33, 0.16);
  border-radius: 8px;
  box-shadow: 0 14px 30px rgba(21, 40, 33, 0.06);
  display: flex;
  flex-direction: column;
  gap: 0.65rem;
  min-height: 100%;
  padding: 18px 16px;
  text-align: center;
}

.wp2026-start-number {
  align-items: center;
  background: var(--wp2026-green);
  border-radius: 999px;
  color: #ffffff;
  display: inline-flex;
  font-size: 0.9rem;
  font-weight: 800;
  height: 2.15rem;
  justify-content: center;
  margin: 0.1rem 0 0;
  width: 2.15rem;
}

.wp2026-start-title {
  font-size: clamp(0.9rem, 1vw, 0.98rem);
  font-weight: 800;
  line-height: 1.25;
  margin: 0;
}

.wp2026-start-step p:not(.wp2026-start-number) {
  font-size: 0.94rem;
  line-height: 1.52;
  margin: 0;
  overflow-wrap: break-word;
  text-align: center;
  white-space: normal;
}

.wp2026-home-hero {
  background:
    linear-gradient(180deg, #ffffff 0%, rgba(255, 255, 255, 0.42) 14%, rgba(255, 255, 255, 0) 28%, rgba(255, 255, 255, 0) 72%, #ffffff 100%),
    radial-gradient(circle at 50% 34%, #d4e6da 0%, #eaf4ee 42%, #ffffff 78%);
  min-height: clamp(260px, 28vw, 350px);
  overflow: hidden;
  padding-block: clamp(44px, 6.2vw, 82px) clamp(48px, 6.5vw, 90px);
  position: relative;
}

.wp2026-home-hero::before {
  background: url("/wp-content/themes/wordpress-2026/assets/lmhg-logo-watermark.png") center / contain no-repeat;
  content: "";
  height: clamp(170px, 18vw, 250px);
  left: 50%;
  opacity: 0.77;
  pointer-events: none;
  position: absolute;
  top: 31%;
  transform: translate(-50%, -50%);
  width: clamp(170px, 18vw, 250px);
  z-index: 0;
}

.wp2026-home-hero > * {
  position: relative;
  z-index: 1;
}

.wp2026-home-hero-columns {
  display: grid;
  gap: clamp(28px, 4vw, 52px);
  grid-template-columns: minmax(0, 1fr);
  max-width: 1180px;
  margin-inline: auto;
  align-items: center;
}

.wp2026-hero-copy {
  display: grid;
  grid-template-columns: max-content max-content;
  column-gap: 0.9rem;
  row-gap: 0;
  align-items: start;
  justify-content: center;
  justify-items: center;
  min-width: 0;
  text-align: center;
  width: 100%;
}

.wp2026-hero-copy > :not(.wp-block-button) {
  grid-column: 1 / -1;
}

.wp2026-hero-copy > .wp-block-button {
  margin-top: 2.5rem !important;
}

.wp2026-kicker {
  color: var(--wp2026-clay);
  font-size: 0.86rem;
  font-weight: 800;
  letter-spacing: 0;
  margin-bottom: 0.8rem;
  text-transform: none;
}

.wp2026-home-title {
  font-size: clamp(2rem, 3.35vw, 3.25rem);
  line-height: 1.02;
  margin: 0 auto;
  max-width: 100%;
  position: relative;
  width: fit-content;
  z-index: 0;
}

.wp2026-page-title::before {
  background: url("/wp-content/themes/wordpress-2026/assets/lmhg-logo-watermark.png") center / contain no-repeat;
  content: "";
  height: clamp(150px, 19vw, 260px);
  left: 50%;
  opacity: 1;
  pointer-events: none;
  position: absolute;
  top: 50%;
  transform: translate(-50%, -50%);
  width: clamp(150px, 19vw, 260px);
  z-index: -1;
}

.wp2026-home-lead,
.wp2026-section-lead {
  font-size: clamp(1.08rem, 1.5vw, 1.25rem);
  line-height: 1.65;
  max-width: 820px;
}

.wp2026-home-lead {
  margin-left: auto;
  margin-right: auto;
  max-width: 760px;
  text-align: center;
}

.wp2026-hero-actions,
.wp2026-closing-actions {
  margin-top: 1.6rem;
}

.wp2026-hero-actions.wp-block-buttons {
  justify-content: center;
  margin-top: 2.5rem !important;
}

.wp2026-closing-actions.wp-block-buttons {
  justify-content: center !important;
  width: 100%;
}

.wp2026-home-services {
  background: #ffffff;
  padding-block: clamp(56px, 6.5vw, 88px);
}

.wp2026-home-services > .wp-block-heading,
.wp2026-home-services > p,
.wp2026-home-closing > .wp-block-heading,
.wp2026-home-closing > p,
.wp2026-home-closing > .wp-block-buttons {
  max-width: 1180px;
  margin-left: auto;
  margin-right: auto;
}

.wp2026-section-title {
  font-size: clamp(1.65rem, 3vw, 2.8rem);
  max-width: 100%;
}

.wp2026-home-services > .wp2026-section-title {
  font-size: min(2.8rem, 2vw) !important;
  line-height: 1.06;
  max-width: calc(100vw - 36px);
  overflow-wrap: normal;
  text-wrap: nowrap;
  white-space: nowrap;
  width: fit-content;
}

.wp2026-service-grid {
  display: grid;
  gap: 28px 22px;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  max-width: 1180px;
  margin: 30px auto 0;
}

.wp2026-service-grid > .wp2026-service-card {
  box-sizing: border-box;
  justify-self: stretch;
  margin-block-start: 0 !important;
  margin-top: 0 !important;
  max-width: none !important;
  min-width: 0;
  width: 100%;
}

.wp2026-service-card {
  background: #faf8f4;
  border: 1px solid rgba(21, 40, 33, 0.12);
  border-radius: 8px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  min-height: 100%;
  min-width: 0;
  padding: 24px 24px 22px;
  width: 100%;
}

.wp2026-service-icon {
  align-items: center;
  background: #ffffff;
  border: 1px solid var(--wp2026-clay);
  border-radius: 999px;
  display: flex;
  height: 78px;
  justify-content: center;
  margin: 0 auto 1.15rem !important;
  width: 78px;
}

.wp2026-service-icon a {
  align-items: center;
  border-radius: inherit;
  display: flex;
  height: 100%;
  justify-content: center;
  text-decoration: none;
  width: 100%;
}

.wp2026-service-icon a:focus-visible {
  outline: 2px solid var(--wp2026-clay);
  outline-offset: 3px;
}

.wp2026-service-icon img {
  display: block;
  margin-inline: auto;
  max-height: 52px;
  max-width: 52px;
  object-fit: contain;
}

.wp2026-service-card-title {
  font-family: Inter, Arial, sans-serif;
  font-size: clamp(1rem, 1.1vw, 1.16rem);
  line-height: 1.25;
  margin-bottom: 0.7rem;
  text-align: center;
}

.wp2026-service-card p {
  font-size: 1rem;
  line-height: 1.55;
}

.wp2026-service-link a {
  border: 1px solid var(--wp2026-clay);
  border-radius: 999px;
  display: inline-flex;
  font-weight: 800;
  padding: 0.42rem 0.82rem;
  text-decoration: none;
  transition: background-color 160ms ease, color 160ms ease, border-color 160ms ease;
}

.wp2026-service-link a:hover {
  background: var(--wp2026-green);
  border-color: var(--wp2026-clay);
  color: #ffffff;
}

.wp2026-service-link {
  margin-top: auto;
  padding-top: 1rem;
  text-align: center;
}

.wp2026-home-closing {
  background: linear-gradient(180deg, #dce9df 0%, #d3e4d9 100%);
  border-bottom: 1px solid #000000;
  border-top: 1px solid #000000;
  padding-block: clamp(50px, 6vw, 78px);
}

.page-template-location-access-page .wp2026-home-closing {
  margin-left: calc(50% - 50vw) !important;
  margin-right: calc(50% - 50vw) !important;
  width: auto !important;
}

.wp2026-template-location-access-page {
  overflow-x: hidden;
  overflow-x: clip;
}

/* Service-page pilot sections mirror the homepage system with page-specific density. */
.page-template-service-page header.wp-block-template-part,
.page-template-specialty-page header.wp-block-template-part {
  box-shadow: 0 1px 0 rgba(21, 40, 33, 0.08), 0 12px 30px rgba(21, 40, 33, 0.045);
}

.page-template-service-page .lmhg-main-content,
.page-template-specialty-page .lmhg-main-content {
  background:
    linear-gradient(180deg, #ffffff 0%, rgba(255, 255, 255, 0.42) 12%, rgba(255, 255, 255, 0) 30%, rgba(255, 255, 255, 0) 70%, #ffffff 100%) top / 100% clamp(470px, 46vw, 680px) no-repeat,
    radial-gradient(circle at 50% 8rem, #d4e6da 0%, #eaf4ee 42%, #ffffff 78%) top / 100% clamp(470px, 46vw, 680px) no-repeat,
    #ffffff;
  overflow: hidden;
