/* Baseline LMHG footer rebuilt as native Gutenberg block markup. */
footer.wp-block-template-part {
  background: transparent;
  color: var(--wp2026-ink);
  margin-top: 0;
  padding: 0;
}

footer.wp-block-template-part a {
  color: var(--wp2026-clay);
  text-decoration: none;
}

footer.wp-block-template-part a:hover,
footer.wp-block-template-part a:focus-visible {
  color: var(--wp2026-green);
  text-decoration: none;
}

footer.wp-block-template-part a:focus-visible {
  outline: 2px solid var(--wp2026-clay);
  outline-offset: 2px;
}

.wp2026-baseline-footer {
  --wp2026-footer-badge-offset: clamp(30px, 2.25vw, 34px);
  --wp2026-footer-after-badges: clamp(30px, 2.25vw, 34px);
  background-color: #ffffff;
  background-image: none;
  box-shadow: none;
  color: var(--wp2026-ink);
  overflow: hidden;
  padding: var(--wp2026-footer-badge-offset) max(18px, calc((100vw - 1180px) / 2)) 28px;
}

.wp2026-baseline-footer.alignfull {
  margin-left: 0 !important;
  margin-right: 0 !important;
}

.wp2026-baseline-footer > .alignwide {
  max-width: 1180px;
}

.wp2026-baseline-footer__top,
.wp2026-baseline-footer__main.wp-block-columns {
  position: relative;
}

.wp2026-baseline-footer__top {
  align-items: center;
  background: transparent;
  border: 0;
  border-radius: 0;
  display: flex !important;
  gap: 0.45rem;
  justify-content: center !important;
  margin-bottom: var(--wp2026-footer-after-badges);
  margin-left: auto;
  margin-right: auto;
  max-width: 1180px;
  padding: 0;
  width: 100%;
}

@media (min-width: 1050px) {
  .wp2026-baseline-footer__top {
    justify-content: center !important;
  }

  .wp2026-baseline-footer__badges {
    justify-content: center;
    flex-wrap: nowrap !important;
  }
}

.wp2026-baseline-footer__badges {
  display: flex !important;
  gap: 0.55rem 0.8rem;
  justify-content: center;
}

.wp2026-baseline-footer__badges {
  margin-block-start: 0 !important;
}

.wp2026-baseline-footer__badge {
  align-items: center;
  background: transparent;
  border: 0;
  border-radius: 0;
  color: var(--wp2026-deep);
  display: inline-flex;
  font-size: 0.88rem;
  font-weight: 700;
  line-height: 1.1;
  margin: 0;
  padding: 0;
  white-space: nowrap;
}

.wp2026-baseline-footer__badge + .wp2026-baseline-footer__badge::before {
  background: rgba(167, 95, 63, 0.62);
  border-radius: 999px;
  content: "";
  height: 0.32rem;
  margin-right: 0.8rem;
  width: 0.32rem;
}

.wp2026-baseline-footer__main.wp-block-columns {
  gap: clamp(28px, 5vw, 56px);
  margin-bottom: clamp(24px, 2.5vw, 32px);
}

.wp2026-baseline-footer__main .wp-block-column {
  margin-block-start: 0 !important;
  min-width: 0;
}

.wp2026-baseline-footer__about {
  background: transparent;
  border: 0;
  border-radius: 0;
  padding: 0;
}

.wp2026-baseline-footer__column-title {
  color: var(--wp2026-deep);
  font-size: clamp(1rem, 1.35vw, 1.18rem);
  line-height: 1.2;
  margin: 0 0 1rem;
  padding-bottom: 0;
  position: relative;
  white-space: normal;
}

.wp2026-baseline-footer__column-title::after {
  content: none;
}

.wp2026-baseline-footer__body,
.wp2026-baseline-footer__copyright,
.wp2026-baseline-footer__insurance-note {
  color: rgba(31, 42, 38, 0.82);
  font-size: 0.95rem;
  line-height: 1.65;
}

.wp2026-baseline-footer__body {
  margin: 0 0 1rem;
}

.wp2026-baseline-footer__office-line {
  margin-bottom: 0.25rem;
}

.wp2026-baseline-footer__link-list,
.wp2026-baseline-footer__legal-list {
  list-style: none;
  margin: 0;
  padding-left: 0;
}

.wp2026-baseline-footer__link-list li + li {
  margin-top: 0.52rem;
}

.wp2026-baseline-footer__link-list a {
  font-size: 0.95rem;
  font-weight: 700;
}

.wp2026-baseline-footer__legal-list a {
  font-size: 0.88rem;
  font-weight: 700;
}

.wp2026-baseline-footer__coverage-list {
  margin-top: 1.2rem;
}

.wp2026-baseline-footer__bottom {
  align-items: center;
  border-top: 0;
  gap: 1rem 2rem;
  margin-top: 0;
  padding-top: 22px;
  position: relative;
}

.wp2026-baseline-footer__bottom::before {
  border-top: 1px solid rgba(49, 88, 74, 0.22);
  content: "";
  left: 50%;
