  top: 0;
  transform: translateX(-50%);
  width: 100vw;
}

.wp2026-baseline-footer__copyright {
  margin: 0;
}

.wp2026-baseline-footer__legal-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.65rem 1rem;
}

.wp2026-baseline-footer__legal-list li {
  margin: 0;
}

.wp2026-baseline-footer__insurance-note {
  margin: 18px auto 0;
  max-width: 860px;
}

